def make_palindrome(s: str) -> str:
    s = list(s)
    n = len(s)
    left, right = 0, n - 1

    while left < right:
        if s[left] != s[right]:
            # Replace the larger character with the smaller one
            if s[left] < s[right]:
                s[right] = s[left]
            else:
                s[left] = s[right]
        left += 1
        right -= 1

    return ''.join(s)
